import{_ as a,o as e,c as o,au as i}from"./chunks/framework.D9yPyvsM.js";const b=JSON.parse('{"title":"quasar-core","description":"Core components and directives for the Kalisio ekosystem","frontmatter":{"title":"quasar-core","description":"Core components and directives for the Kalisio ekosystem"},"headers":[],"relativePath":"packages/quasar-core/index.md","filePath":"packages/quasar-core/index.md"}'),r={name:"packages/quasar-core/index.md"};function d(s,t,n,l,c,p){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="quasar-core" tabindex="-1">quasar-core <a class="header-anchor" href="#quasar-core" aria-label="Permalink to &quot;quasar-core&quot;">​</a></h1><p><em>Core components and directives for the Kalisio ekosystem</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>quasar-core</strong> is the foundation of the quasar-ekosystem. It provides a set of generic UI components and directives built on top of the <a href="https://quasar.dev" target="_blank" rel="noreferrer">Quasar Framework</a>, all automatically registered when the plugin is installed.</p><p>It is organized around 2 modules:</p><ul><li><a href="#components">components</a> — generic UI building blocks (avatar, chip, modal, tabs, tree…)</li><li><a href="#directives">directives</a> — reusable Vue directives (<code>v-hover</code>, <code>v-safe-html</code>)</li><li><a href="#platform">Plarform</a> - a unique object that provides platform, browser, and fingerprint data</li></ul><h3 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h3><p><strong>quasar-core</strong> ships the following generic components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Description</th></tr></thead><tbody><tr><td><code>KAction</code></td><td>Multi-renderer action button (button, item, fab, tab…) with toggle and handler support</td></tr><tr><td><code>KAvatar</code></td><td>Avatar built from a subject — displays initials, an image or an icon</td></tr><tr><td><code>KChip</code></td><td>Chip with label, icon and v-model support</td></tr><tr><td><code>KContent</code></td><td>Dynamically renders a list of components from a content descriptor array or object</td></tr><tr><td><code>KDialog</code></td><td>Confirmation dialog with configurable OK and Cancel actions</td></tr><tr><td><code>KEditor</code></td><td>Form wrapper bound to a Feathers service, supporting create and edit modes</td></tr><tr><td><code>KExpandable</code></td><td>Animated expand/collapse container driven by a prop</td></tr><tr><td><code>KFollower</code></td><td>Overlay component that positions itself relative to a target element</td></tr><tr><td><code>KModal</code></td><td>Modal window with header, scrollable content and footer buttons</td></tr><tr><td><code>KPanel</code></td><td>Horizontal or vertical action bar driven by a content array</td></tr><tr><td><code>KScrollArea</code></td><td>Scroll area with configurable scrollbar style</td></tr><tr><td><code>KSponsor</code></td><td>KDK and Kalisio attribution block</td></tr><tr><td><code>KStamp</code></td><td>Icon and text block with vertical or horizontal layout</td></tr><tr><td><code>KStore</code></td><td>Reactive application store displayed as a tree</td></tr><tr><td><code>KTab</code></td><td>Tab navigation driven by a content object</td></tr><tr><td><code>KTextArea</code></td><td>Expandable text area with scroll</td></tr><tr><td><code>KTree</code></td><td>Hierarchical tree with lazy node loading</td></tr></tbody></table><p>All components are automatically registered globally when the plugin is installed.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install with your preferred package manager:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-DlmE-" id="tab-iMTAH1j" checked><label data-title="pnpm" for="tab-iMTAH1j">pnpm</label><input type="radio" name="group-DlmE-" id="tab-05sQyKJ"><label data-title="npm" for="tab-05sQyKJ">npm</label><input type="radio" name="group-DlmE-" id="tab-nWGHz5t"><label data-title="yarn" for="tab-nWGHz5t">yarn</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @kalisio/quasar-core</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @kalisio/quasar-core</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @kalisio/quasar-core</span></span></code></pre></div></div></div>',13)])])}const u=a(r,[["render",d]]);export{b as __pageData,u as default};
